UPDATE LQ_USER_QUEST
SET STATUS = #{status},
    COMPLETED_AT = #{completedAt}
WHERE USER_QUEST_ID = #{userQuestId}

UPDATE LQ_USER_QUEST
SET STATUS = #{status},
    STARTED_AT = #{startedAt},
    DUE_AT = #{dueAt},
    COMPLETED_AT = #{completedAt}
WHERE USER_QUEST_ID = #{userQuestId}

UPDATE LQ_USER_QUEST
SET STATUS = #{status},
    STARTED_AT = #{startedAt},
    DUE_AT = #{dueAt},
    COMPLETED_AT = #{completedAt}
WHERE USER_QUEST_ID = #{userQuestId}

UPDATE LQ_USER_QUEST
SET STATUS = #{status},
    COMPLETED_AT = #{completedAt}
WHERE USER_QUEST_ID = #{userQuestId}
  AND STATUS != 'COMPLETED'
